    options:[`$H = 15.3 \\text{ m}; T = 3.53 \\text{ s}; R = 35.3 \\text{ m}$`, `$H = 10.2 \\text{ m}; T = 2.00 \\text{ s}; R = 20.0 \\text{ m}$`, `$H = 30.6 \\text{ m}; T = 7.07 \\text{ s}; R = 35.3 \\text{ m}$`, `$H = 5.1 \\text{ m}; T = 1.77 \\text{ s}; R = 17.7 \\text{ m}$`],
